class Solution:
    def shortestPalindrome(self, s):
        n = len(s)
        rev = s[::-1]
        # longest prefix of s that is a palindrome: largest k with s[:k] palindrome
        for k in range(n, 0, -1):
            if s[:k] == s[:k][::-1]:
                break
        else:
            k = 0
        return rev[:n - k] + s

