class Solution:
    def shortestPalindrome(self, s):
        if not s:
            return s
        combined = s + '#' + s[::-1]
        fail = [0] * len(combined)
        for i in range(1, len(combined)):
            j = fail[i - 1]
            while j > 0 and combined[i] != combined[j]:
                j = fail[j - 1]
            if combined[i] == combined[j]:
                j += 1
            fail[i] = j
        longest = fail[-1]
        return s[longest:][::-1] + s

