var shortestPalindrome = function(s) {
    if (s.length === 0) return s;
    const combined = s + '#' + s.split('').reverse().join('');
    const fail = new Array(combined.length).fill(0);
    for (let i = 1; i < combined.length; i++) {
        let j = fail[i - 1];
        while (j > 0 && combined[i] !== combined[j]) j = fail[j - 1];
        if (combined[i] === combined[j]) j++;
        fail[i] = j;
    }
    const longest = fail[fail.length - 1];
    const tail = s.slice(longest).split('').reverse().join('');
    return tail + s;
};
